  // 민원 텍스트에서 카테고리 감지 (keyword 기반)
  const detectCategory = (text: string): string => {
    const t = text.toLowerCase();
    if (t.includes('생기부') || t.includes('나이스') || t.includes('출결') || t.includes('지각')) return 'records';
    if (t.includes('급식') || t.includes('음식') || t.includes('반찬') || t.includes('식판')) return 'lunch';
    if (t.includes('체육') || t.includes('피구') || t.includes('달리기') || t.includes('운동')) return 'pe';
    if (t.includes('안경') || t.includes('치료비') || t.includes('부상') || t.includes('배상')) return 'injury';
    if (t.includes('자리') || t.includes('짝꿍') || t.includes('모둠') || t.includes('배치')) return 'seating';
    if (t.includes('학폭') || t.includes('폭력') || t.includes('왕따') || t.includes('조롱')) return 'bullying';
    return 'general';
  };

